#include <iostream>#include <string>using namespace std;int main() {// Array de nomesstring nomes[3] = {"Tommy", "Jerryzinho", "Spike"};    // Array de idades    int idades[3] = {5, 2, 7};    cout << "=== PERSONAGENS DO JOGO 🐱🐭 ===" << endl;    cout << endl;    // Mostrar todos os personagens    for (int i = 0; i < 3; i++) {        cout << "Nome: " << nomes[i] << endl;        cout << "Idade: " << idades[i] << " anos" << endl;        cout << "------------------------" << endl;    }    cout << endl;    // Escolher personagem    int escolha;    cout << "Escolhe um personagem (0, 1 ou 2): ";    cin >> escolha;    cout << endl;    if (escolha >= 0 && escolha < 3) {        cout << "Voce escolheu: " << nomes[escolha] << endl;        cout << "Idade: " << idades[escolha] << " anos" << endl;    } else {        cout << "Escolha invalida 😅" << endl;    }    return 0;}